 1→worker_processes auto;
 2→pid /tmp/nginx.pid;
 3→
 4→events {
 5→    worker_connections 1024;
 6→}
 7→
 8→http {
 9→    include      /etc/nginx/mime.types;
10→    default_type application/octet-stream;
11→    sendfile     on;
12→
13→    access_log /dev/stdout combined;
14→    error_log  /dev/stderr warn;
15→
16→    server {
17→        listen 80;
18→        root  /var/www/kapow;
19→        index index.html;
20→
21→        # Proxy GraphQL and REST API to the Go server
22→        location /graphql {
23→            proxy_pass         http://localhost:8081;
24→            proxy_set_header   Host $host;
25→            proxy_set_header   X-Real-IP $remote_addr;
26→        }
27→
28→        location /api/ {
29→            proxy_pass         http://localhost:8081;
30→            proxy_set_header   Host $host;
31→            proxy_set_header   X-Real-IP $remote_addr;
32→        }
33→
34→        # SPA fallback — unknown paths serve index.html for client-side routing
35→        location / {
36→            try_files $uri /index.html;
37→        }
38→    }
39→}
